/**
 * n8n Code 节点：把下载好的视频（二进制）喂给 Yunwu Gemini generateContent
 * 输出：{ gemini_body }
 */

function pickBinaryKey(bin) {
  if (!bin || typeof bin !== "object") return "";
  if (bin.video) return "video";
  if (bin.data) return "data";
  const keys = Object.keys(bin);
  return keys.length ? keys[0] : "";
}

function ensureBase64FromBinary(itemIndex, binaryKey) {
  const bin = $input.all()[itemIndex].binary?.[binaryKey];
  if (!bin) throw new Error(`Binary key \"${binaryKey}\" not found`);
  if (bin.data && typeof bin.data === "string" && bin.data.length > 50) {
    return bin.data;
  }
  return null;
}

const systemText = `# Role
你是一位精通**视频逆向工程**与**商业叙事逻辑拆解**的专家。你的核心能力是透过像素表象，提取视频的“爆款基因”。

# Goal
输出一份标准的 JSON 格式分析报告。这份报告将作为“母版”，指导下游 AI 在保留原视频运镜、节奏和情绪逻辑的前提下，填入全新的产品生成新视频。

# Output Format (JSON Schema)
请严格遵守以下 JSON 结构输出，不要包含任何 Markdown 代码块以外的闲聊：
\`\`\`json
{
  \"meta\": {
    \"art_style\": \"全局艺术风格\",
    \"render_quality\": \"渲染质量\",
    \"mood_atmosphere\": \"核心情绪氛围\",
    \"total_duration\": \"视频总时长\"
  },
  \"scene_breakdown\": [
    {
      \"id\": 1,
      \"time_range\": \"00:00 - 00:XX\",
      \"visual_specs\": {
        \"camera\": \"镜头信息\",
        \"subject_action\": \"主体动作\",
        \"lighting_environment\": \"环境细节\",
        \"auxiliary_elements\": \"辅助元素\"
      },
      \"abstract_logic\": {
        \"narrative_role\": \"叙事功能\",
        \"universal_instruction\": \"通用生成指令，包含[HERO_PRODUCT]变量\"
      }
    }
  ]
}
\`\`\`
`;

const items = $input.all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const bin = item.binary || {};
  const binaryKey = pickBinaryKey(bin);
  if (!binaryKey) {
    throw new Error("No binary data found. Make sure the download node outputs binary (e.g., data/video).");
  }

  const mimeType = bin[binaryKey]?.mimeType || "video/mp4";

  let base64 = ensureBase64FromBinary(i, binaryKey);
  if (!base64) {
    if (!this?.helpers?.getBinaryDataBuffer) {
      throw new Error(
        `Binary has no .data and this.helpers.getBinaryDataBuffer is unavailable.`
      );
    }
    const buf = await this.helpers.getBinaryDataBuffer(i, binaryKey);
    base64 = buf.toString("base64");
  }

  const gemini_body = {
    systemInstruction: { parts: [{ text: systemText }] },
    contents: [
      {
        role: "user",
        parts: [
          {
            inlineData: {
              mimeType,
              data: base64
            }
          }
        ]
      }
    ],
    generationConfig: {
      responseMimeType: "application/json"
    }
  };

  out.push({
    json: {
      ...item.json,
      script_id: $('Webhook').item.json.body.script_id,
      video_url: $('Webhook').item.json.body.video_url,
      api_key: $('Webhook').item.json.body.api_key,
      workflow_id: $('Webhook').item.json.body.workflow_id,
      gemini_body,
      _debug_binary: {
        binaryKey,
        mimeType,
        base64_length: base64.length
      }
    },
    binary: item.binary
  });
}

return out;

/**
 * 解析 Gemini generateContent 的返回
 * 输出：analysis（已解析对象）
 */

function getText(root) {
  const r = Array.isArray(root) ? root[0] : root;
  return r?.candidates?.[0]?.content?.parts?.[0]?.text || "";
}

function tryParseJsonWithFixes(text) {
  const errs = [];
  try {
    return { obj: JSON.parse(text), fixedText: text, errs };
  } catch (e) {
    errs.push("direct JSON.parse failed: " + e.message);
  }

  let fixed = text.replace(
    /("time_range"\s*:\s*)([^"\s][^,\n}]*)/g,
    (m, p1, p2) => {
      const cleaned = String(p2).trim().replace(/^"+|"+$/g, "");
      return `${p1}"${cleaned}"`;
    }
  );

  try {
    return { obj: JSON.parse(fixed), fixedText: fixed, errs };
  } catch (e) {
    errs.push("fixed JSON.parse failed: " + e.message);
  }

  return { obj: null, fixedText: fixed, errs };
}

const items = $input.all();
const out = [];

for (const item of items) {
  const root = item.json;
  const text = getText(root);

  if (!text) {
    out.push({
      json: {
        ...item.json,
        analysis: null,
        parse_ok: false,
        errors: ["No candidates[0].content.parts[0].text found"]
      }
    });
    continue;
  }

  const { obj, fixedText, errs } = tryParseJsonWithFixes(text);

  out.push({
    json: {
      ...item.json,
      parse_ok: !!obj,
      analysis: obj,
      _raw_text: text,
      _fixed_text: fixedText,
      errors: obj ? [] : errs
    }
  });
}

return out;

